+// Particle system for environmental effects: torch embers, forge sparks, healing particles, dust motes, dripping water.
+// Each particle is 1-2px sized, has simple physics (gravity, velocity), and room-specific ambient particles.
+
+class Particle {
+  constructor(x, y, vx, vy, size, color, lifetime, gravity = 0.1) {
+    this.x = x;
+    this.y = y;
+    this.vx = vx;
+    this.vy = vy;
+    this.size = size;
+    this.color = color;
+    this.lifetime = lifetime;
+    this.age = 0;
+    this.gravity = gravity;
+  }
+
+  update() {
+    this.vy += this.gravity;
+    this.x += this.vx;
+    this.y += this.vy;
+    this.age++;
+  }
+
+  isAlive() {
+    return this.age < this.lifetime;
+  }
+}
+
+class ParticleSystem {
+  constructor(room) {
+    this.room = room;
+    this.particles = [];
+    this.spawnTimer = 0;
+  }
+
+  spawnParticle(type) {
+    let x, y, vx, vy, size, color, lifetime;
+    switch(type) {
+      case 'torchEmber':
+        x = Math.random() * this.room.width;
+        y = this.room.height - 20 + Math.random() * 10;
+        vx = (Math.random() - 0.5) * 0.3;
+        vy = -Math.random() * 1.5 - 0.5;
+        size = 1 + Math.random();
+        color = 'rgba(255,140,0,' + (0.5 + Math.random() * 0.5) + ')';
+        lifetime = 60 + Math.floor(Math.random() * 30);
+        break;
+      case 'forgeSpark':
+        x = Math.random() * this.room.width;
+        y = this.room.height - 10 + Math.random() * 5;
+        vx = (Math.random() - 0.5) * 1;
+        vy = -Math.random() * 2 - 1;
+        size = 1 + Math.random();
+        color = 'rgba(255,215,0,' + (0.7 + Math.random() * 0.3) + ')';
+        lifetime = 40 + Math.floor(Math.random() * 20);
+        break;
+      case 'healingParticle':
+        x = Math.random() * this.room.width;
+        y = Math.random() * this.room.height;
+        vx = (Math.random() - 0.5) * 0.2;
+        vy = -Math.random() * 0.5;
+        size = 1 + Math.random();
+        color = 'rgba(0,255,0,' + (0.3 + Math.random() * 0.4) + ')';
+        lifetime = 80 + Math.floor(Math.random() * 40);
+        break;
+      case 'dustMote':
+        x = Math.random() * this.room.width;
+        y = Math.random() * this.room.height;
+        vx = (Math.random() - 0.5) * 0.1;
+        vy = (Math.random() - 0.5) * 0.1;
+        size = 1;
+        color = 'rgba(200,200,200,' + (0.1 + Math.random() * 0.2) + ')';
+        lifetime = 100 + Math.floor(Math.random() * 50);
+        break;
+      case 'drippingWater':
+        x = Math.random() * this.room.width;
+        y = 0;
+        vx = 0;
+        vy = Math.random() * 1 + 0.5;
+        size = 1;
+        color = 'rgba(173,216,230,0.6)';
+        lifetime = this.room.height / vy + 20;
+        break;
+      default:
+        return;
+    }
+    this.particles.push(new Particle(x, y, vx, vy, size, color, lifetime));
+  }
+
+  update() {
+    this.spawnTimer++;
+    // Spawn particles depending on room type
+    if (this.spawnTimer % 5 === 0) {
+      if (this.room.type === 'torchRoom') {
+        this.spawnParticle('torchEmber');
+      } else if (this.room.type === 'forgeRoom') {
+        this.spawnParticle('forgeSpark');
+      } else if (this.room.type === 'healingRoom') {
+        this.spawnParticle('healingParticle');
+      } else if (this.room.type === 'dustyRoom') {
+        this.spawnParticle('dustMote');
+      } else if (this.room.type === 'waterRoom') {
+        this.spawnParticle('drippingWater');
+      }
+    }
+
+    this.particles = this.particles.filter(p => {
+      p.update();
+      return p.isAlive();
+    });
+  }
+
+  draw(ctx) {
+    for (const p of this.particles) {
+      ctx.fillStyle = p.color;
+      ctx.beginPath();
+      ctx.arc(p.x, p.y, p.size, 0, 2 * Math.PI);
+      ctx.fill();
+    }
+  }
+}
+
+export default ParticleSystem;
